// Custom struct for sockaddr_in to be used as a key in std::map
// This ensures correct comparison and ordering for map operations
struct SockAddrKey {
    sockaddr_in addr;

    SockAddrKey() {
        memset(&addr, 0, sizeof(addr)); // Initialize to zeros
    }

    SockAddrKey(const sockaddr_in& a) : addr(a) {}

    // Comparison operator for std::map
    bool operator<(const SockAddrKey& other) const {
        // Compare family, port, and then IP address
        if (addr.sin_family != other.addr.sin_family) return addr.sin_family < other.addr.sin_family;
        if (addr.sin_port != other.addr.sin_port) return addr.sin_port < other.sin_port;
        // For IPv4, compare the s_addr field
        return addr.sin_addr.s_addr < other.addr.sin_addr.s_addr;
    }

    // Equality operator for convenience (optional for map, but good practice)
    bool operator==(const SockAddrKey& other) const {
        return addr.sin_family == other.addr.sin_family &&
               addr.sin_port == other.addr.sin_port &&
               addr.sin_addr.s_addr == other.addr.sin_addr.s_addr;
    }
};

