// Calculates the dot product of two Vector3s
float dot(const Vector3& a, const Vector3& b) {
    return a.x * b.x + a.y * b.y + a.z * b.z;
}

// Simple ray-sphere intersection check.
// Returns true if the ray intersects the sphere, and updates hit_point with the intersection location.
bool ray_sphere_intersect(const Vector3& ray_origin, const Vector3& ray_direction,
                          const Vector3& sphere_center, float sphere_radius, Vector3& hit_point) {
    // Vector from ray origin to sphere center
    Vector3 m = {ray_origin.x - sphere_center.x, ray_origin.y - sphere_center.y, ray_origin.z - sphere_center.z};

    float b = dot(m, ray_direction);
    float c = dot(m, m) - sphere_radius * sphere_radius;

    // If ray origin is outside sphere (c > 0) and ray points away (b > 0), no intersection
    if (c > 0.0f && b > 0.0f) return false;

    float discriminant = b * b - c;

    // Negative discriminant means ray misses sphere
    if (discriminant < 0.0f) return false;

    // Compute the smallest t value of intersection (t = distance along ray)
    float t = -b - std::sqrt(discriminant);

    // If t is negative, ray started inside sphere or sphere is behind ray origin.
    // For hit detection from outside, we might want to ignore negative t.
    // For simplicity, we assume we want any intersection. If t < 0, it means the origin is inside
    // the sphere, and t=0 represents the origin.
    if (t < 0.0f) t = 0.0f; // Clamp to 0 if starting inside to register a hit at origin

    // Calculate the hit point
    hit_point = {ray_origin.x + ray_direction.x * t,
                 ray_origin.y + ray_direction.y * t,
                 ray_origin.z + ray_direction.z * t};
    return true;
}

